10	        * { margin: 0; padding: 0; box-sizing: border-box; }
11	        body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; background: #0a0a0a; color: #fff; min-height: 100vh; }
12	
13	        .header { background: linear-gradient(135deg, #0a1628 0%, #0d1f3c 100%); border-bottom: 1px solid #1a2a4a; padding: 20px 30px; display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 15px; }
14	        .header-left { display: flex; align-items: center; gap: 20px; }
15	        .header-logo img { height: 42px; }
16	        .header-title h1 { font-size: 22px; font-weight: 700; color: #fff; }
17	        .header-title p { font-size: 12px; color: #6b8cba; margin-top: 3px; }
18	        .header-brand { font-size: 11px; color: #1d6fa8; text-align: right; line-height: 1.6; }
19	
20	        .filter-bar { background: #0d0d0d; border-bottom: 1px solid #1a1a1a; padding: 14px 30px; display: flex; align-items: center; gap: 12px; flex-wrap: wrap; }
21	        .filter-label { font-size: 11px; color: #555; text-transform: uppercase; letter-spacing: 1px; white-space: nowrap; }
22	        .filter-group, .compare-group { display: flex; gap: 8px; flex-wrap: wrap; }
23	        .compare-group { margin-left: auto; }
24	        .filter-btn, .compare-btn { padding: 6px 14px; border-radius: 20px; border: 1px solid #222; background: transparent; color: #777; font-size: 12px; cursor: pointer; transition: all 0.2s; }
25	        .filter-btn:hover { border-color: #1d6fa8; color: #1d6fa8; }
26	        .filter-btn.active { background: #1d6fa8; border-color: #1d6fa8; color: #fff; }
27	        .compare-btn:hover { border-color: #f59e0b; color: #f59e0b; }
28	        .compare-btn.active { background: #f59e0b; border-color: #f59e0b; color: #000; font-weight: 600; }
29	
30	        .content { padding: 30px; max-width: 1400px; margin: 0 auto; }
31	
32	        .summary-cards { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 15px; margin-bottom: 30px; }
33	        .summary-card { background: #111; border: 1px solid #1a1a1a; border-radius: 12px; padding: 20px; position: relative; overflow: hidden; }
34	        .summary-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: #1d6fa8; }
35	        .card-label { font-size: 11px; color: #555; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 10px; }
36	        .card-value { font-size: 28px; font-weight: 700; color: #fff; margin-bottom: 6px; }
37	        .card-change { font-size: 12px; }
38	        .card-change.up { color: #10b981; }
39	        .card-change.down { color: #ef4444; }
40	        .card-change.neutral { color: #555; }
41	
42	        .section { margin-bottom: 40px; }
43	        .section-title { font-size: 12px; font-weight: 600; color: #555; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 20px; padding-bottom: 10px; border-bottom: 1px solid #1a1a1a; }
44	
45	        .chart-card { background: #111; border: 1px solid #1a1a1a; border-radius: 12px; padding: 25px; margin-bottom: 20px; }
46	        .chart-card-title { font-size: 13px; color: #777; margin-bottom: 20px; }
47	        .chart-wrapper { position: relative; height: 300px; }
